import { useNavigate } from "react-router-dom";
import "./AddNew.css";

function AddNew() {
  const navigate = useNavigate();

  return (
    <div className="add-wrapper">
      <div className="add-card">

        {/* ⭐ BACK ARROW — goes to Profile page */}
        <div className="back-btn" onClick={() => navigate("/profile")}>
          ← Back
        </div>

        <h2 className="add-title">Add New Expense</h2>

        <div className="add-buttons">

          {/* Travel Expense Card */}
          <div
            className="expense-card"
            onClick={() => navigate("/add/travel")}
          >
            <h3>Travel Expense</h3>
            <p>Add travel details like date, from/to, amount.</p>
          </div>

          {/* Ticket Expense Card */}
          <div
            className="expense-card"
            onClick={() => navigate("/add/ticket")}
          >
            <h3>Ticket Expense</h3>
            <p>Add ticketing details like assigned to & amount.</p>
          </div>

        </div>
      </div>
    </div>
  );
}

export default AddNew;
